import { useEffect, useState } from 'react';
import API from '../services/api';
import LeadTable from '../components/LeadTable';
import LeadsChart from '../charts/LeadsChart';
import Loader from '../components/Loader';

const EMPTY_FORM = {
  fullName: '', email: '', phoneNumber: '', country: '',
  courseInterested: '', leadSource: '', assignedCounselor: '',
  leadStatus: 'New', priority: 'Medium', notes: ''
};

function Leads() {
  const [leads, setLeads] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingLead, setEditingLead] = useState(null);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    getLeads();
  }, []);

  const getLeads = async () => {
    try {
      const res = await API.get('/leads');
      setLeads(res.data);
    } catch {
      setError('Failed to load leads.');
    } finally {
      setLoading(false);
    }
  };

  const openAdd = () => {
    setEditingLead(null);
    setForm(EMPTY_FORM);
    setShowModal(true);
  };

  const openEdit = (lead) => {
    setEditingLead(lead);
    setForm({ ...EMPTY_FORM, ...lead });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!form.fullName) { alert('Full name is required.'); return; }
    setSaving(true);
    try {
      if (editingLead) {
        const res = await API.put(`/leads/${editingLead._id}`, form);
        setLeads(leads.map((l) => (l._id === editingLead._id ? res.data : l)));
      } else {
        const res = await API.post('/leads', form);
        setLeads([res.data, ...leads]);
      }
      setShowModal(false);
    } catch {
      alert('Failed to save lead.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this lead?')) return;
    try {
      await API.delete(`/leads/${id}`);
      setLeads(leads.filter((l) => l._id !== id));
    } catch {
      alert('Failed to delete lead.');
    }
  };

  if (loading) return <Loader />;

  return (
    <div>
      <div className="page-header">
        <h2>Lead Management</h2>
        <button className="btn-primary" onClick={openAdd}>+ Add Lead</button>
      </div>

      {error && <div className="error-msg">{error}</div>}

{Array.isArray(leads) &&
  leads.length > 0 && (
    <LeadsChart leads={leads} />
)}

      <LeadTable leads={leads} onEdit={openEdit} onDelete={handleDelete} />

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <h3>{editingLead ? 'Edit Lead' : 'Add New Lead'}</h3>

            <div className="form-grid">
              {[
                ['fullName', 'Full Name'],
                ['email', 'Email'],
                ['phoneNumber', 'Phone Number'],
                ['country', 'Country'],
                ['courseInterested', 'Course Interested'],
                ['leadSource', 'Lead Source'],
                ['assignedCounselor', 'Assigned Counselor'],
              ].map(([key, label]) => (
                <div key={key} className="form-group">
                  <label>{label}</label>
                  <input
                    value={form[key] || ''}
                    onChange={(e) => setForm({ ...form, [key]: e.target.value })}
                    placeholder={label}
                  />
                </div>
              ))}

              <div className="form-group">
                <label>Status</label>
                <select value={form.leadStatus} onChange={(e) => setForm({ ...form, leadStatus: e.target.value })}>
                  {['New', 'Contacted', 'Interested', 'Not Interested', 'Admitted', 'Needs Attention'].map(s => (
                    <option key={s}>{s}</option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Priority</label>
                <select value={form.priority} onChange={(e) => setForm({ ...form, priority: e.target.value })}>
                  {['Low', 'Medium', 'High'].map(p => <option key={p}>{p}</option>)}
                </select>
              </div>

              <div className="form-group full-width">
                <label>Notes</label>
                <textarea
                  value={form.notes || ''}
                  onChange={(e) => setForm({ ...form, notes: e.target.value })}
                  placeholder="Notes..."
                  rows={3}
                />
              </div>
            </div>

            <div className="modal-actions">
              <button onClick={() => setShowModal(false)}>Cancel</button>
              <button className="btn-primary" onClick={handleSave} disabled={saving}>
                {saving ? 'Saving...' : 'Save'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Leads;
